const allItems = $input.all();

// Append mode stacks all rows - should have 33 items total
// Sprint rows have 'Sprint' field, RAID rows have 'Category' field

const sprint4 = allItems
  .map(i => i.json)
  .filter(j => j.Sprint === 'Sprint 4');

const sprint3 = allItems
  .map(i => i.json)
  .filter(j => j.Sprint === 'Sprint 3');

const raidRows = allItems
  .map(i => i.json)
  .filter(j => j.Category && !j.Sprint);

// Calculations
const s4Done = sprint4.filter(s => s.Status === 'Done').length;
const s4InProgress = sprint4.filter(s => s.Status === 'In Progress').length;
const s4NotStarted = sprint4.filter(s => 
  s.Status === 'Not Started' || s.Status === 'Pending'
).length;
const s4Blocked = sprint4.filter(s => s.Blocked === 'Yes').length;
const s4Total = sprint4.length;
const s4CompletionPct = s4Total > 0 
  ? Math.round((s4Done / s4Total) * 100) : 0;

const s3DonePoints = sprint3
  .filter(s => s.Status === 'Done')
  .reduce((sum, s) => sum + Number(s['Story Points'] || 0), 0);

const s4DonePoints = sprint4
  .filter(s => s.Status === 'Done')
  .reduce((sum, s) => sum + Number(s['Story Points'] || 0), 0);

const openHighRisks = raidRows
  .filter(r => r.Priority === 'High' && r.Status === 'Open').length;

let rag = 'GREEN';
if (s4CompletionPct < 30 || s4Blocked > 3) rag = 'RED';
else if (s4CompletionPct < 60 || s4Blocked >= 2) rag = 'AMBER';

const velocityChange = s3DonePoints > 0
  ? Math.round(((s4DonePoints - s3DonePoints) / s3DonePoints) * 100) : 0;

return [{
  json: {
    summary: {
      sprint: 'Sprint 4',
      rag_status: rag,
      completion_pct: s4CompletionPct,
      total_stories: s4Total,
      done: s4Done,
      in_progress: s4InProgress,
      not_started: s4NotStarted,
      blocked_count: s4Blocked,
      sprint3_velocity: s3DonePoints,
      sprint4_velocity_so_far: s4DonePoints,
      velocity_change: velocityChange + '%',
      open_high_risks: openHighRisks
    },
    sprint4_stories: sprint4,
    raid_items: raidRows
      .filter(r => r.Status === 'Open')
      .slice(0, 5),
    debug: {
      total_items: allItems.length,
      sprint4_count: sprint4.length,
      sprint3_count: sprint3.length,
      raid_count: raidRows.length
    }
  }
}];

