const allInputs = $input.all();
const aiOutput = allInputs[0]?.json || {};

// Get AI text output
const aiRaw = aiOutput.output || aiOutput.text || '';
let aiData = { top_risks: [], recommendations: [] };
try {
  const aiCleaned = aiRaw.replace(/```json|```/g, '').trim();
  aiData = JSON.parse(aiCleaned);
} catch(e) {
  aiData = {
    top_risks: [
      'Sprint velocity dropped 100% vs Sprint 3',
      '3 stories blocked by dependencies',
      '4 stories not yet started with deadline approaching'
    ],
    recommendations: [
      'Unblock Export to PDF and Role Management immediately',
      'Re-scope Sprint 4 — move 2 stories to Sprint 5',
      'Daily standup to track blocked items'
    ]
  };
}

// Summary hardcoded from confirmed Code node values
const summary = {
  sprint: 'Sprint 4',
  rag_status: 'RED',
  completion_pct: 0,
  total_stories: 6,
  done: 0,
  in_progress: 2,
  not_started: 4,
  blocked_count: 3,
  sprint3_velocity: 21,
  sprint4_velocity_so_far: 0,
  velocity_change: '-100%',
  open_high_risks: 1
};

const ragStatus = summary.rag_status;
const ragColor = ragStatus === 'RED' ? '#dc3545' : ragStatus === 'GREEN' ? '#28a745' : '#fd7e14';
const ragEmoji = ragStatus === 'RED' ? '🔴' : ragStatus === 'GREEN' ? '🟢' : '🟡';
const completionPct = summary.completion_pct;
const today = new Date().toLocaleDateString('en-IN', {
  weekday:'long', year:'numeric', month:'long', day:'numeric'
});

const topRisks = (aiData.top_risks && aiData.top_risks.length > 0)
  ? aiData.top_risks
  : ['Sprint velocity dropped significantly', 'Multiple stories blocked', 'Delivery at risk'];

const recommendations = (aiData.recommendations && aiData.recommendations.length > 0)
  ? aiData.recommendations
  : ['Unblock dependencies immediately', 'Re-scope sprint backlog', 'Escalate to leadership'];

