        <div class="vel-item">
          <div class="vel-value">${summary.sprint3_velocity} pts</div>
          <div class="vel-label">Sprint 3 Completed</div>
        </div>
        <div class="vel-item">
          <div class="vel-value" style="color:${ragColor};">${summary.sprint4_velocity_so_far} pts</div>
          <div class="vel-label">Sprint 4 So Far</div>
        </div>
        <div class="vel-item">
          <div class="vel-value" style="color:${ragColor};">${summary.velocity_change}</div>
