    <strong>Zero human effort — fully autonomous PMO reporting</strong>
  </div>
</div>
</body>
</html>`;

return [{
  json: {
    html: htmlReport,
    subject: `${ragEmoji} ${summary.sprint} Health Report — ${ragStatus} — ${new Date().toLocaleDateString()}`,
    rag: ragStatus
  }
